  panel.querySelector("[data-layout-preview-palette-results]").textContent = optionLabel(paletteResultLimitOptions, settings.paletteResultLimit, settings.paletteResultLimit);
  panel.querySelector("[data-layout-preview-palette-placement]").textContent = optionLabel(palettePlacementOptions, settings.palettePlacement, settings.palettePlacement);
