const performanceQuickActionById = new Map(performanceQuickActionDefinitions.map((action) => [action.id, action]));

function performanceQuickActionForCommand(commandId) {
  return performanceQuickActionById.get(commandPerformanceQuickActionIds.get(commandId)) || null;
}

function performanceQuickActionIsActive(action) {
  return Boolean(action && state.settings[action.key] === action.value);
}

function performanceQuickActionPaletteSignature() {
  const parts = [];
  for (const action of performanceQuickActionDefinitions) {
    appendSignatureValue(parts, action.id);
    appendSignatureValue(parts, state.settings[action.key]);
  }
  return parts.join("");
}

const performanceToolbarToggleIds = [
  ["performanceMode.on", "performanceMode.off", () => state.settings.performanceMode],
  ["adaptivePerformance.on", "adaptivePerformance.off", () => state.settings.adaptivePerformance],
  ["terminalStartup.fast", "terminalStartup.balanced", () => state.settings.terminalStartupMode === "fast"],
  ["terminalPauseInactiveOutput.on", "terminalPauseInactiveOutput.off", () => state.settings.terminalPauseInactiveOutput],
  ["terminalSmoothResumedOutput.on", "terminalSmoothResumedOutput.off", () => state.settings.terminalSmoothResumedOutput],
  ["browserSuspendInactive.on", "browserSuspendInactive.off", () => state.settings.browserSuspendInactive],
  ["reduceMotion.on", "reduceMotion.off", () => state.settings.reduceMotion]
];

function runPerformanceQuickAction(actionId) {
  const action = performanceQuickActionById.get(actionId);
  if (!action) return false;
  const changed = updateSettings({ [action.key]: action.value });
  if (!changed) {
    toast(action.already);
    return false;
  }
  if (state.inspectorMode === "settings") renderSettingsInspector();
  toast(action.applied);
  return true;
}

function performanceQuickToolbarActions(toolbarAction) {
  return performanceToolbarToggleIds.map(([onId, offId, isOn]) => {
    const action = performanceQuickActionById.get(isOn() ? offId : onId);
    const button = toolbarAction(action.label, () => runPerformanceQuickAction(action.id), false, action.title);
    button.dataset.performanceQuickAction = action.id;
    return button;
  });
}

function performanceSetupSummaryForSettings(settings) {
  const normalized = normalizeSettings({
    ...state.settings,
    ...(settings || {})
  });
  const backgroundEffects = optionLabel(backgroundEffectsOptions, normalized.backgroundEffects, normalized.backgroundEffects);
  const backgroundChrome = optionLabel(backgroundChromeOptions, normalized.backgroundChromeMode, normalized.backgroundChromeMode);
  const toolbar = optionLabel(toolbarModeOptions, normalized.toolbarMode, normalized.toolbarMode);
  const toolbarLabels = optionLabel(toolbarLabelModeOptions, normalized.toolbarLabelMode, normalized.toolbarLabelMode);
  const topbar = optionLabel(topbarStyleOptions, normalized.topbarStyle, normalized.topbarStyle);
  const toolbarButtons = optionLabel(toolbarButtonStyleOptions, normalized.toolbarButtonStyle, normalized.toolbarButtonStyle);
  const tabBar = optionLabel(tabBarStyleOptions, normalized.tabBarStyle, normalized.tabBarStyle);
  const sidebar = optionLabel(sidebarStyleOptions, normalized.sidebarStyle, normalized.sidebarStyle);
  const sidebarTools = optionLabel(sidebarToolOptions, normalized.sidebarToolMode, normalized.sidebarToolMode);
  const inspector = optionLabel(inspectorStyleOptions, normalized.inspectorStyle, normalized.inspectorStyle);
  const overlay = optionLabel(overlayStyleOptions, normalized.overlayStyle, normalized.overlayStyle);
  const switcher = optionLabel(switcherStyleOptions, normalized.switcherStyle, normalized.switcherStyle);
  const toastPlacement = optionLabel(toastPlacementOptions, normalized.toastPlacement, normalized.toastPlacement);
  const palette = optionLabel(paletteDensityOptions, normalized.paletteDensity, normalized.paletteDensity);
  const paletteActions = optionLabel(paletteQuickActionsModeOptions, normalized.paletteQuickActionsMode, normalized.paletteQuickActionsMode);
  const paletteDetail = optionLabel(paletteDetailModeOptions, normalized.paletteDetailMode, normalized.paletteDetailMode);
  const paletteResults = optionLabel(paletteResultLimitOptions, normalized.paletteResultLimit, normalized.paletteResultLimit);
  const palettePlacement = optionLabel(palettePlacementOptions, normalized.palettePlacement, normalized.palettePlacement);
  const controls = optionLabel(paneActionOptions, normalized.paneActionMode, normalized.paneActionMode);
  const paneSurface = optionLabel(paneSurfaceStyleOptions, normalized.paneSurfaceStyle, normalized.paneSurfaceStyle);
  const dividers = optionLabel(paneDividerSizeOptions, normalized.paneDividerSize, normalized.paneDividerSize);
  const dividerStyle = optionLabel(paneDividerStyleOptions, normalized.paneDividerStyle, normalized.paneDividerStyle);
  const spacing = optionLabel(paneSpacingOptions, normalized.paneSpacing, normalized.paneSpacing);
  const activePane = optionLabel(activePaneEmphasisOptions, normalized.activePaneEmphasis, normalized.activePaneEmphasis);
  const motionSpeed = optionLabel(chromeMotionOptions, normalized.chromeMotionMode, normalized.chromeMotionMode);
  const depth = optionLabel(interfaceDepthOptions, normalized.interfaceDepth, normalized.interfaceDepth);
  const browserChrome = browserChromeModeLabel(normalized.browserChromeMode);
  return {
    mode: normalized.performanceMode ? "Tuned" : "Balanced",
    adaptiveGuard: normalized.adaptivePerformance ? "On" : "Off",
    motion: normalized.performanceMode || normalized.reduceMotion ? `Reduced / ${motionSpeed}` : motionSpeed,
    chrome: `${normalized.density === "compact" ? "Compact" : "Comfortable"} / ${toolbar} / ${toolbarLabels} labels / ${topbar} top bar / ${toolbarButtons} / ${tabBar} tab bar / ${sidebar} sidebar / ${sidebarTools} rail / ${inspector} settings / ${overlay} overlays / ${switcher} switcher / ${toastPlacement} toasts / ${palette} palette / ${paletteActions} actions / ${paletteDetail} details / ${paletteResults} results / ${palettePlacement} placement / ${paneSurface} panes`,
    topbar,
    toolbarLabels,
    inspectorStyle: inspector,
    overlayStyle: overlay,
    switcherStyle: switcher,
    toastPlacement,
    paletteDensity: palette,
    paletteQuickActions: paletteActions,
    paletteDetail,
    paletteResults,
    palettePlacement,
    controls,
    paneSurface,
    dividers,
    dividerStyle,
    paneSpacing: spacing,
    activePane,
    depth,
    background: `${backgroundEffects} / ${backgroundChrome} chrome / ${normalized.backgroundOpacity}% / ${normalized.backgroundBlur}px soften`,
    backgroundChrome,
    terminalStartup: optionLabel(terminalStartupOptions, normalized.terminalStartupMode, normalized.terminalStartupMode),
    inactiveOutput: normalized.terminalPauseInactiveOutput ? "Paused" : "Live",
    resume: normalized.terminalSmoothResumedOutput ? "Smooth" : "Immediate",
    cursor: normalized.terminalCursorBlink ? "Blinking" : "Steady cursor",
    inactiveBrowsers: normalized.browserSuspendInactive ? "Suspended" : "Live",
    browserChrome,
    padding: `${normalized.terminalPadding}px padding`,
    history: `${normalized.terminalScrollback.toLocaleString()} history`
  };
}

function performanceHealthCheckById(checkId) {
  return performanceHealthCheckDefinitions.find((check) => check.id === checkId) || null;
}

function performanceHealthCheckNeedsFix(check) {
  return Boolean(check?.issue?.());
}

function performanceHealthCheckUpdates(check) {
  if (!performanceHealthCheckNeedsFix(check)) return null;
  const updates = check.updates?.() || {};
  return Object.keys(updates).length ? updates : null;
}

function performanceHealthIssueCount() {
  return performanceHealthCheckDefinitions.filter(performanceHealthCheckNeedsFix).length;
}

function performanceHealthIssueCountLabel(count = performanceHealthIssueCount()) {
  if (count === 0) return "Ready";
  return `${count} fix${count === 1 ? "" : "es"}`;
}

function performanceHealthPaletteSignature() {
  const parts = [];
  appendSignatureValue(parts, performanceHealthIssueCount());
  for (const check of performanceHealthCheckDefinitions) {
    appendSignatureValue(parts, check.id);
    appendSignatureValue(parts, performanceHealthCheckNeedsFix(check));
    appendSignatureValue(parts, check.meta?.() || "");
  }
  return parts.join("");
}

function performanceHealthCombinedUpdates() {
  const updates = {};
  for (const check of performanceHealthCheckDefinitions) {
    Object.assign(updates, performanceHealthCheckUpdates(check) || {});
  }
  return Object.keys(updates).length ? updates : null;
}

function applyPerformanceHealthFix(checkId) {
  const check = performanceHealthCheckById(checkId);
  const updates = performanceHealthCheckUpdates(check);
  if (!check || !updates) {
    toast(check ? `${check.label} is already tuned.` : "Performance fix not found.");
    return false;
  }
  const changed = updateSettings(updates, { immediate: true });
  if (!changed) {
    toast(`${check.label} is already tuned.`);
    return false;
  }
  if (state.inspectorMode === "settings") scheduleSettingsInspectorRender({ ifChanged: true });
  toast(`${check.label} tuned.`);
  return true;
}

function applyPerformanceHealthFixes() {
  const updates = performanceHealthCombinedUpdates();
  if (!updates) {
    toast("Performance health is already tuned.");
    return false;
  }
  const changed = updateSettings(updates, { immediate: true });
  if (!changed) {
    toast("Performance health is already tuned.");
    return false;
  }
  if (state.inspectorMode === "settings") scheduleSettingsInspectorRender({ ifChanged: true });
  toast("Performance health fixes applied.");
  return true;
}

function performanceSetupSettingsAreDefault() {
  return settingsKeysMatchDefaults(performanceSetupSettings);
}

function performanceSetupPayload(settingsSource = state.settings) {
  const source = {
    ...state.settings,
    ...(settingsSource || {})
  };
  const settings = {};
  for (const key of performanceSetupSettings) settings[key] = source[key];
  return {
    version: 1,
    type: "cmux-performance-setup",
    summary: performanceSetupSummaryForSettings(settings),
    settings
  };
}

async function copyPerformanceSetupPayload(
  payloadModel = performanceSetupPayload(),
  toastText = "Performance setup copied.",
  dialogMessage = "Clipboard access is unavailable. The current performance setup is shown below."
) {
  const payload = JSON.stringify(payloadModel, null, 2);
  if (await writeClipboardText(payload)) {
    toast(toastText);
    return true;
  }
  await showTextDialog({
    title: "Performance setup",
    message: dialogMessage,
    value: payload,
    confirmLabel: "Close",
    multiline: true,
    readOnly: true
  });
  return false;
}

async function copyPerformanceSetup() {
  return copyPerformanceSetupPayload(performanceSetupPayload(), "Performance setup copied.");
}

function performanceSetupSettingUpdateFromValue(key, raw) {
  if (key === "terminalStartupMode") return optionIdAllowed(terminalStartupOptions, raw) ? raw : null;
  if (key === "chromeMotionMode") return optionIdAllowed(chromeMotionOptions, raw) ? raw : null;
  if (key === "density") return ["comfortable", "compact"].includes(raw) ? raw : null;
  if (key === "toolbarMode") return optionIdAllowed(toolbarModeOptions, raw) ? raw : null;
  if (key === "toolbarLabelMode") return optionIdAllowed(toolbarLabelModeOptions, raw) ? raw : null;
  if (key === "topbarStyle") return optionIdAllowed(topbarStyleOptions, raw) ? raw : null;
  if (key === "toolbarButtonStyle") return optionIdAllowed(toolbarButtonStyleOptions, raw) ? raw : null;
  if (key === "tabBarStyle") return optionIdAllowed(tabBarStyleOptions, raw) ? raw : null;
  if (key === "sidebarStyle") return optionIdAllowed(sidebarStyleOptions, raw) ? raw : null;
  if (key === "sidebarToolMode") return optionIdAllowed(sidebarToolOptions, raw) ? raw : null;
  if (key === "inspectorStyle") return optionIdAllowed(inspectorStyleOptions, raw) ? raw : null;
  if (key === "overlayStyle") return optionIdAllowed(overlayStyleOptions, raw) ? raw : null;
  if (key === "switcherStyle") return optionIdAllowed(switcherStyleOptions, raw) ? raw : null;
  if (key === "toastPlacement") return optionIdAllowed(toastPlacementOptions, raw) ? raw : null;
  if (key === "paletteDensity") return optionIdAllowed(paletteDensityOptions, raw) ? raw : null;
  if (key === "paletteQuickActionsMode") return optionIdAllowed(paletteQuickActionsModeOptions, raw) ? raw : null;
  if (key === "paletteDetailMode") return optionIdAllowed(paletteDetailModeOptions, raw) ? raw : null;
  if (key === "paletteResultLimit") return optionIdAllowed(paletteResultLimitOptions, raw) ? raw : null;
  if (key === "palettePlacement") return optionIdAllowed(palettePlacementOptions, raw) ? raw : null;
  if (key === "paneActionMode") return optionIdAllowed(paneActionOptions, raw) ? raw : null;
  if (key === "paneSurfaceStyle") return optionIdAllowed(paneSurfaceStyleOptions, raw) ? raw : null;
  if (key === "paneDividerSize") return optionIdAllowed(paneDividerSizeOptions, raw) ? raw : null;
  if (key === "paneDividerStyle") return optionIdAllowed(paneDividerStyleOptions, raw) ? raw : null;
  if (key === "paneSpacing") return optionIdAllowed(paneSpacingOptions, raw) ? raw : null;
  if (key === "activePaneEmphasis") return optionIdAllowed(activePaneEmphasisOptions, raw) ? raw : null;
  if (key === "backgroundOpacity") {
    if (raw === null || raw === "" || typeof raw === "boolean" || typeof raw === "object") return null;
    const value = Number(raw);
    return Number.isFinite(value) ? clamp(Math.round(value), 0, 42) : null;
  }
  if (key === "backgroundBlur") {
    if (raw === null || raw === "" || typeof raw === "boolean" || typeof raw === "object") return null;
    const value = Number(raw);
    return Number.isFinite(value) ? clamp(Math.round(value), 0, 12) : null;
  }
  if (key === "backgroundEffects") return optionIdAllowed(backgroundEffectsOptions, raw) ? raw : null;
  if (key === "backgroundChromeMode") return optionIdAllowed(backgroundChromeOptions, raw) ? raw : null;
  if (key === "interfaceDepth") return optionIdAllowed(interfaceDepthOptions, raw) ? raw : null;
  if (key === "browserChromeMode") return optionIdAllowed(browserChromeOptions, raw) ? raw : null;
  if (key === "terminalPadding") {
    const value = Number(raw);
    return Number.isFinite(value) ? clamp(Math.round(value), 0, 16) : null;
  }
  if (key === "terminalScrollback") {
    const value = Number(raw);
    return Number.isFinite(value) ? clamp(Math.round(value), 2000, 50000) : null;
  }
  if (performanceSetupBooleanSettings.has(key)) return typeof raw === "boolean" ? raw : null;
  return null;
}

function performanceSetupUpdatesFromPayload(payload) {
  const parsed = importedObject(payload);
  const source = importedObject(parsed?.settings) || parsed;
  if (!source) return null;
  const updates = {};
  for (const key of performanceSetupSettings) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;
    const value = performanceSetupSettingUpdateFromValue(key, source[key]);
    if (value === null) return null;
    updates[key] = value;
  }
  return Object.keys(updates).length ? updates : null;
}

function applyPerformanceSetupUpdates(updates, options = {}) {
  if (!updates) {
    toast("Clipboard does not contain performance setup.");
    return false;
  }
  const changed = updateSettings(updates, { immediate: true });
  if (!changed) {
    toast(options.alreadyText || "Performance setup already matches.");
    return false;
  }
  if (state.inspectorMode === "settings") scheduleSettingsInspectorRender({ ifChanged: true });
  toast(options.toastText || "Performance setup applied.");
  return true;
}

function resetPerformanceSetupSettings() {
  const updates = {};
  for (const key of performanceSetupSettings) updates[key] = defaultSettings[key];
  const changed = updateSettings(updates, { immediate: true });
  if (!changed) {
    toast("Performance setup already uses defaults.");
    return false;
  }
  if (state.inspectorMode === "settings") scheduleSettingsInspectorRender({ ifChanged: true });
  toast("Performance setup reset.");
  return true;
}

async function pastePerformanceSetup() {
  const clipboard = await readClipboardText();
  if (!clipboard) {
    toast("Clipboard is empty.");
    return false;
  }
  try {
    const parsed = JSON.parse(clipboard);
    return applyPerformanceSetupUpdates(performanceSetupUpdatesFromPayload(parsed));
  } catch {
    toast("Clipboard does not contain performance setup.");
    return false;
  }
}

function performanceTuningPresetById(presetId) {
  return performanceTuningPresets.find((candidate) => candidate.id === presetId) || null;
}

function performanceTuningPresetSettings(preset) {
  return performanceSetupUpdatesFromPayload({ settings: preset?.settings });
}

function performanceTuningPresetProfileSettings(preset) {
  const settings = performanceTuningPresetSettings(preset);
  if (!settings) return null;
  return normalizeSettings({
    ...state.settings,
    ...settings
  });
}

function savedSettingsProfileForPerformanceTuningPreset(preset) {
  const settings = performanceTuningPresetProfileSettings(preset);
  if (!settings) return null;
  return state.savedSettingsProfiles.find((profile) => settingsProfileMatchesSettings(profile, settings)) || null;
}

function performanceTuningPresetProfileSaveTitle(preset, savedProfile = savedSettingsProfileForPerformanceTuningPreset(preset)) {
  if (!preset) return "Choose a performance tuning preset first.";
  if (savedProfile) return `${savedProfile.label} already saves ${preset.label}.`;
  if (savedSettingsProfilesFull()) return settingsProfileLimitTitle();
  return "Save this performance tuning preset as a reusable profile.";
}

function performanceTuningPresetProfileSaveSearchText(preset, settings = performanceTuningPresetSettings(preset), savedProfile = null) {
  const summary = performanceSetupSummaryForSettings(settings || {});
  return normalizeSettingsQuery(`performance tuning preset save profile reusable settings speed lag smooth ${savedProfile ? "saved unavailable " : savedSettingsProfilesFull() ? "limit full unavailable " : "ready "}${settingsProfileSaveStateSearch(savedProfile)} ${preset?.label || ""} ${preset?.body || ""} ${summary.mode} ${summary.motion} ${summary.background} ${summary.backgroundChrome} ${summary.inactiveOutput} ${summary.inactiveBrowsers} ${summary.browserChrome} ${summary.history}`);
}

function performanceTuningPresetSearchText(preset, settings = performanceTuningPresetSettings(preset), savedProfile = null) {
  const summary = performanceSetupSummaryForSettings(settings || {});
  const active = isActivePerformanceTuningPreset(preset);
  return normalizeSettingsQuery([
    `performance tuning preset setup apply copy speed lag smooth low motion ${active ? "active current unavailable " : "ready "}speed snappy balanced calm live panes workspace chrome density toolbar top bar style button style ghost tab bar quiet banded sidebar style settings panel inspector overlay command palette menus dialogs toast feedback placement bottom right left top palette density compact balanced roomy result limit focused balanced extended results placement position top center wide quick actions auto hidden command list details metadata shortcuts compact labels switcher workspace pane keyboard hud pane surface controls split dividers resize grip line minimal active pane emphasis spacing gap gutter padding surface depth shadow background opacity effects glass flat chrome readable soft immersive terminal output browser preview pane chrome compact content full controls tabs address suspend history scrollback`,
    performanceTuningPresetProfileSaveSearchText(preset, settings, savedProfile),
    preset?.label,
    preset?.body,
    summary.mode,
    summary.adaptiveGuard,
    summary.motion,
    summary.chrome,
    summary.topbar,
    summary.inspectorStyle,
    summary.overlayStyle,
    summary.switcherStyle,
    summary.toastPlacement,
    summary.paletteDensity,
    summary.paletteQuickActions,
    summary.paletteDetail,
    summary.paletteResults,
    summary.palettePlacement,
    summary.controls,
    summary.paneSurface,
    summary.dividers,
    summary.dividerStyle,
    summary.paneSpacing,
    summary.activePane,
    summary.depth,
    summary.background,
    summary.backgroundChrome,
    summary.terminalStartup,
    summary.inactiveOutput,
    summary.resume,
    summary.cursor,
    summary.inactiveBrowsers,
    summary.browserChrome,
    summary.padding,
    summary.history
  ].join(" "));
}

function isActivePerformanceTuningPreset(preset) {
  const settings = performanceTuningPresetSettings(preset);
  if (!settings) return false;
  return Object.entries(settings).every(([key, value]) => state.settings[key] === value);
}

function performanceTuningPresetTitle(preset, active) {
  if (!preset) return "Choose a performance tuning preset first.";
  if (active) return `${preset.label} tuning is already active.`;
  return `Apply ${preset.label} performance tuning.`;
}

function performanceTuningPresetCopySearchText(preset, settings = performanceTuningPresetSettings(preset)) {
  const summary = performanceSetupSummaryForSettings(settings || {});
  return normalizeSettingsQuery(`performance tuning preset copy setup clipboard json speed lag smooth motion speed snappy balanced calm workspace chrome top bar style tab bar quiet banded sidebar style settings panel inspector overlay command palette menus dialogs toast feedback placement bottom right left top palette density compact balanced roomy search results quick actions auto hidden command list details metadata shortcuts compact labels result limit focused balanced extended placement position top center wide switcher workspace pane keyboard hud pane surface split dividers resize grip line minimal active pane emphasis spacing gap gutter background opacity effects chrome readable soft immersive browser pane compact content full controls tabs address ${preset?.label || ""} ${preset?.body || ""} ${summary.mode} ${summary.motion} ${summary.chrome} ${summary.topbar} ${summary.inspectorStyle} ${summary.overlayStyle} ${summary.switcherStyle} ${summary.toastPlacement} ${summary.paletteDensity} ${summary.paletteQuickActions} ${summary.paletteDetail} ${summary.paletteResults} ${summary.palettePlacement} ${summary.paneSurface} ${summary.dividers} ${summary.dividerStyle} ${summary.paneSpacing} ${summary.activePane} ${summary.background} ${summary.backgroundChrome} ${summary.inactiveOutput} ${summary.inactiveBrowsers} ${summary.browserChrome} ${summary.history}`);
}

function performanceTuningPresetCopyTitle(preset) {
  return `Copy ${preset?.label || "this"} tuning preset as performance setup JSON.`;
}

function updatePerformanceTuningPresetButton(button, preset) {
  const settings = performanceTuningPresetSettings(preset);
  if (!settings) return false;
  const active = isActivePerformanceTuningPreset(preset);
  const savedProfile = savedSettingsProfileForPerformanceTuningPreset(preset);
  const card = button.closest(".performance-tune-card");
  let changed = false;
  if (card) changed = toggleClassIfChanged(card, "is-active", active) || changed;
  changed = setDisabledIfChanged(button, active) || changed;
  changed = setTitleIfChanged(button, performanceTuningPresetTitle(preset, active)) || changed;
  setAttributeIfChanged(button, "aria-pressed", active ? "true" : "false");
  const status = button.querySelector(".performance-tune-status");
  if (status) changed = setTextIfChanged(status, active ? "Active" : "") || changed;
  const search = performanceTuningPresetSearchText(preset, settings, savedProfile);
  if (button.dataset.settingsSearch !== search) {
    button.dataset.settingsSearch = search;
    updateSettingsSearchIndexItemSearch(button, search);
    changed = true;
  }
  if (card && card.dataset.settingsSearch !== search) {
    card.dataset.settingsSearch = search;
    updateSettingsSearchIndexItemSearch(card, search);
    changed = true;
  }
  const save = card?.querySelector(`[data-performance-tuning-save="${preset.id}"]`);
  if (save) {
    const saveSearch = performanceTuningPresetProfileSaveSearchText(preset, settings, savedProfile);
    changed = setSettingsActionLabel(save, savedProfile ? "Saved" : "Save") || changed;
    changed = setDisabledIfChanged(save, Boolean(savedProfile) || savedSettingsProfilesFull()) || changed;
    changed = toggleClassIfChanged(save, "primary", Boolean(savedProfile)) || changed;
    changed = setTitleIfChanged(save, performanceTuningPresetProfileSaveTitle(preset, savedProfile)) || changed;
    if (save.dataset.settingsSearch !== saveSearch) {
      save.dataset.settingsSearch = saveSearch;
      updateSettingsSearchIndexItemSearch(save, saveSearch);
      changed = true;
    }
  }
  const copy = card?.querySelector(`[data-performance-tuning-copy="${preset.id}"]`);
  if (copy) {
    const copySearch = performanceTuningPresetCopySearchText(preset, settings);
    changed = setTitleIfChanged(copy, performanceTuningPresetCopyTitle(preset)) || changed;
    if (copy.dataset.settingsSearch !== copySearch) {
      copy.dataset.settingsSearch = copySearch;
      updateSettingsSearchIndexItemSearch(copy, copySearch);
      changed = true;
    }
  }
  return changed;
}

function refreshPerformanceTuningPresetGrid(root = elements.inspectorBody) {
  if (!root?.querySelectorAll) return false;
  let changed = false;
  for (const button of root.querySelectorAll(".performance-tune-preset[data-performance-tuning-preset]")) {
    const preset = performanceTuningPresetById(button.dataset.performanceTuningPreset);
    if (!preset) continue;
    changed = updatePerformanceTuningPresetButton(button, preset) || changed;
  }
  return changed;
}

function applyPerformanceTuningPreset(presetId) {
  const preset = performanceTuningPresetById(presetId);
  const settings = performanceTuningPresetSettings(preset);
  if (!preset || !settings) {
    toast("Performance tuning preset not found.");
    return false;
  }
  return applyPerformanceSetupUpdates(settings, {
    toastText: `${preset.label} tuning applied.`,
    alreadyText: `${preset.label} tuning already active.`
  });
}

function savePerformanceTuningPresetProfile(presetId) {
  const preset = performanceTuningPresetById(presetId);
  if (!preset) {
    toast("Performance tuning preset not found.");
    return null;
  }
  const existing = savedSettingsProfileForPerformanceTuningPreset(preset);
  if (existing) {
    toast(`${existing.label} profile already saves ${preset.label}.`);
    return existing;
  }
  if (savedSettingsProfilesFull()) {
    toast(settingsProfileLimitTitle());
    return null;
  }
  const saved = upsertSavedSettingsProfile({
    id: createSettingsProfileId(),
    label: defaultSettingsProfileName(`${preset.label} speed`),
    settings: performanceTuningPresetProfileSettings(preset),
    createdAt: Date.now()
  });
  if (!saved) return null;
  renderSettingsInspector();
  toast(`${saved.label} profile saved.`);
  return saved;
}

function copyPerformanceTuningPreset(presetId) {
  const preset = performanceTuningPresetById(presetId);
  const settings = performanceTuningPresetSettings(preset);
  if (!preset || !settings) {
    toast("Performance tuning preset not found.");
    return false;
  }
  return copyPerformanceSetupPayload(
    performanceSetupPayload(settings),
    `${preset.label} tuning copied.`,
    "Clipboard access is unavailable. The tuning preset is shown below."
  );
}

function performanceTuningPresetActiveSignature() {
  return performanceSetupSettings.map((key) => state.settings[key]).join("\u001f");
}

async function copyPerformanceDiagnostics() {
  const payload = JSON.stringify(performanceDiagnosticsPayload(), null, 2);
  if (await writeClipboardText(payload)) {
    toast("Performance diagnostics copied.");
    return;
  }
  await showTextDialog({
    title: "Performance diagnostics",
    message: "Clipboard access is unavailable. The diagnostics report is shown below.",
    value: payload,
    confirmLabel: "Close",
    multiline: true,
    readOnly: true
  });
}

function activeSettingsPresetLabel() {
  return settingsPresets.find((preset) => isActiveSettingsPreset(preset))?.label || "Custom";
}

function activeSavedSettingsProfile() {
  return state.savedSettingsProfiles.find((profile) => isActiveSettingsProfile(profile)) || null;
}

function savedSettingsProfilesFull() {
  return state.savedSettingsProfiles.length >= savedSettingsProfilesLimit;
}

function settingsProfileLimitTitle() {
  return `Profile limit is ${savedSettingsProfilesLimit}. Delete one first.`;
}

function applySettingsProfileSaveLimit(button, availableTitle = "Save the current setup as a reusable profile.") {
  if (!button) return button;
  const full = savedSettingsProfilesFull();
  button.disabled = full;
  button.title = full ? settingsProfileLimitTitle() : availableTitle;
  return button;
}

function activeSettingsSetupModel() {
  const saved = activeSavedSettingsProfile();
  if (saved) {
    return {
      label: saved.label,
      kind: "Saved profile",
      baseName: `${saved.label} copy`
    };
  }
  const presetLabel = activeSettingsPresetLabel();
  if (presetLabel !== "Custom") {
    return {
      label: presetLabel,
      kind: "Built-in profile",
      baseName: `${presetLabel} setup`
    };
  }
  return {
    label: "Custom",
    kind: "Unsaved setup",
    baseName: "Custom setup"
  };
}

function activeSettingsSetupLabel() {
  return activeSettingsSetupModel().label;
}

function savedSettingsProfileCountLabel() {
  return `${state.savedSettingsProfiles.length}/${savedSettingsProfilesLimit}`;
}

function settingsProfileSaveStateMeta(savedProfile = null) {
  if (savedProfile) return `Already saved / ${savedProfile.label}`;
  return savedSettingsProfileCountLabel();
}

function settingsProfileSaveStateSearch(savedProfile = null) {
  if (savedProfile) return `${savedSettingsProfileCountLabel()} profiles saved reusable unavailable ${savedProfile.label}`;
  return `${savedSettingsProfileCountLabel()} profiles ${savedSettingsProfilesFull() ? "limit full unavailable" : "capacity ready"}`;
}

function saveQuickSetupProfile() {
  const setup = activeSettingsSetupModel();
  return saveCurrentSettingsProfile({
    title: "Save current setup",
    message: "Save the current colors, layout, terminal, browser, and performance settings as a reusable profile.",
    baseName: setup.baseName
  });
}

async function applyAndSaveCleanFastProfile() {
  if (savedSettingsProfilesFull()) {
    toast(settingsProfileLimitTitle());
    return null;
  }
  const preset = settingsPresetById("simpleFast");
  const changed = preset ? updateSettings(preset.settings) : false;
  const label = await showTextDialog({
    title: "Save clean + fast setup",
    message: "Apply the clean speed preset now, then save it as a reusable Settings profile.",
    value: defaultSettingsProfileName("Clean + fast setup"),
    placeholder: "Clean + fast setup",
    confirmLabel: "Save"
  });
  if (!label) {
    if (changed) {
      renderSettingsInspector();
      toast("Clean + fast settings applied.");
    }
    return;
  }
  const saved = upsertSavedSettingsProfile({
    id: createSettingsProfileId(),
    label,
    settings: state.settings,
    createdAt: Date.now()
  });
  renderSettingsInspector();
  if (!saved) return;
  toast(changed ? "Clean + fast profile saved and applied." : "Clean + fast profile saved.");
}

function settingsPresetById(presetId) {
  return settingsPresets.find((preset) => preset.id === presetId) || null;
}

function isSettingsPresetIdActive(presetId) {
  const preset = settingsPresetById(presetId);
  return Boolean(preset && isActiveSettingsPreset(preset));
}

function accentModeLabel() {
  const source = normalizeCustomPaletteColor(state.settings.accent) ? "Custom color" : "Preset color";
  return `${source} / ${optionLabel(accentIntensityOptions, state.settings.accentIntensity, state.settings.accentIntensity)}`;
}

function performanceModeLabel() {
  if (state.settings.performanceMode) return "Tuned";
  if (state.settings.adaptivePerformance) return state.performanceGuardTriggered ? "Auto tuned" : "Watching";
  return "Manual";
}

function workspaceCountLabel() {
  const count = state.data?.workspaces?.length || 0;
  return `${count} workspace${count === 1 ? "" : "s"}`;
}

function quickCustomizationLibraryEntries(entries = dataStorageEntries()) {
  const iconById = {
    commandSnippets: "commands",
    settingsProfiles: "profiles",
    workspaceBlueprints: "blueprints",
    customColors: "appearance",
    savedBackgrounds: "background"
  };
  const queryById = {
    commandSnippets: "command snippets",
    settingsProfiles: "saved settings profiles",
    workspaceBlueprints: "workspace blueprints",
    customColors: "saved colors",
    savedBackgrounds: "saved backgrounds"
  };
  return entries
    .filter((entry) => Object.hasOwn(iconById, entry.id))
    .map((entry) => ({
      ...entry,
      icon: iconById[entry.id],
      query: queryById[entry.id] || entry.terms
    }));
}

function quickCustomizationLibrarySummary(entries = quickCustomizationLibraryEntries()) {
  const savedCount = savedDataItemCount();
  const bytes = entries.reduce((sum, entry) => sum + entry.bytes, 0);
  if (savedCount === 0) return "No saved customization yet.";
  return `${savedCount} saved item${savedCount === 1 ? "" : "s"} / ${formatBytes(bytes)}`;
}

function quickCustomizationLibraryItem(entry) {
  const item = document.createElement("button");
  item.className = `quick-overview-library-item${entry.bytes === 0 ? " is-empty" : ""}`;
  item.type = "button";
  item.dataset.settingsSearch = normalizeSettingsQuery(`quick setup customization library saved ${entry.label} ${entry.count} ${entry.terms}`);
  item.title = `Open ${entry.label}. ${entry.count}; ${formatBytes(entry.bytes)} local.`;
  item.setAttribute("aria-label", item.title);
  item.innerHTML = `
    <span class="quick-overview-library-icon" aria-hidden="true"></span>
    <span class="quick-overview-library-copy">
      <b></b>
      <em></em>
    </span>
  `;
  item.querySelector(".quick-overview-library-icon").innerHTML = quickActionIconMarkup(entry.icon);
  item.querySelector("b").textContent = entry.label;
  item.querySelector("em").textContent = entry.count;
  item.onclick = () => openSettingsCategory(entry.category, { query: entry.query, focusSearch: false });
  return item;
}

function setQuickScopeItemState(panel, scopeId, options = {}) {
  const item = panel.querySelector(`[data-quick-scope-item="${scopeId}"]`);
  if (!item) return;
  const model = activeBackgroundPanelViewModel(scopeId);
  toggleClassIfChanged(item, "is-active", Boolean(options.active));
  toggleClassIfChanged(item, "is-muted", Boolean(options.muted));
  toggleClassIfChanged(item, "has-image", model.hasBackground);
  toggleClassIfChanged(item, "is-mixed", model.mixed);
  setStylePropertyIfChanged(item, "--quick-scope-background-image", model.image);
  setStylePropertyIfChanged(item, "--quick-scope-background-repeat", model.repeat);
  setStylePropertyIfChanged(item, "--quick-scope-background-size", model.size);
  setStylePropertyIfChanged(item, "--quick-scope-background-position", model.position);
  setDisabledIfChanged(item, Boolean(options.disabled));
  const option = backgroundApplyTargetOption(scopeId);
  const title = formatMessage("quickGuide.backgroundTargetTitle", { label: option.label });
  setTitleIfChanged(item, title);
  setAttributeIfChanged(item, "aria-label", `${title}. ${option.meta}.`);
  item.onclick = () => openBackgroundTargetSettings(scopeId);
}

function openBackgroundTargetSettings(target = "app") {
  const scope = normalizeBackgroundApplyTarget(target);
  const option = backgroundApplyTargetOption(scope);
  const status = activeBackgroundTargetStatus(scope);
  if (!status.canTarget) {
    toast(formatMessage("quickGuide.backgroundTargetUnavailable", { label: option.label }));
    return false;
  }
  state.backgroundApplyTarget = scope;
  openSettingsCategory("appearance", { query: "background image", focusSearch: false });
  return true;
}

function quickOverviewControlButton(label, run, options = {}) {
  const button = settingsActionButton(label, run, "", options.search || "");
  button.disabled = Boolean(options.disabled);
  button.title = options.title || button.title;
  button.setAttribute("aria-label", button.title);
  return button;
}

function scheduleQuickSettingsRefresh(options = {}) {
  if (state.inspectorMode !== "settings" || state.settingsCategory !== "quick") return false;
  scheduleSettingsInspectorRender({ ifChanged: true, ...options });
  return true;
}

function refreshQuickSettingsAfterAction(result, options = {}) {
  if (result !== false) scheduleQuickSettingsRefresh(options);
  return result;
}

function quickOverviewControlsPanel(options = {}) {
  const panel = document.createElement("div");
  const actions = options.actions || [];
  panel.className = [
    "quick-overview-controls",
    actions.length > 5 ? "has-scroll-actions" : "",
    options.className || ""
  ].filter(Boolean).join(" ");
  panel.dataset.settingsSearch = normalizeSettingsQuery(options.search || "");
  panel.innerHTML = `
    <span class="quick-overview-controls-copy">
      <b></b>
      <em></em>
    </span>
    <span class="quick-overview-controls-actions"></span>
  `;
  panel.querySelector("b").textContent = options.title || "";
  panel.querySelector("em").textContent = options.meta || "";
  panel.querySelector(".quick-overview-controls-actions").append(...actions);
  return panel;
}

function quickWorkspaceControlsPanel(workspace, terminalCount = 0, browserCount = 0) {
  const hasWorkspace = Boolean(workspace);
  const workspaceName = workspaceDisplayTitle(workspace, "No workspace");
  const folderTitle = workspace ? folderName(workspace.cwd) : "";
  const branchTitle = workspaceBranchNameSuggestion(workspace);
  const paneTitle = workspacePaneSuggestedTitle(workspace);
  const pageTitle = workspaceBrowserPageTitleSuggestion(workspace);
  const paneSummary = `${terminalCount} terminal${terminalCount === 1 ? "" : "s"} / ${browserCount} browser${browserCount === 1 ? "" : "s"}`;
  const disabledTitle = "Open a workspace before changing workspace setup.";
  const refreshQuick = refreshQuickSettingsAfterAction;
  const actions = [
    quickOverviewControlButton("Rename", renameActiveWorkspace, {
      disabled: !hasWorkspace,
      title: workspaceRenameActionTitle(workspace),
      search: workspaceRenameActionSearchText("rename", workspace, "quick setup")
    }),
    quickOverviewControlButton("Use folder", async () => {
      if (!workspace || !folderTitle) return false;
      const changed = await renameWorkspaceTo(folderTitle, workspace.id);
      toast(changed ? "Workspace name set from folder." : "Workspace already uses the folder name.");
      return refreshQuick(changed);
    }, {
      disabled: !hasWorkspace || !folderTitle || folderTitle === workspace?.title,
      title: workspaceUseFolderNameTitle(workspace),
      search: workspaceRenameActionSearchText("useFolder", workspace, "quick setup")
    }),
    quickOverviewControlButton("Use branch", async () => {
      if (!workspace || !branchTitle) return false;
      const changed = await renameWorkspaceTo(branchTitle, workspace.id);
      toast(changed ? "Workspace name set from Git branch." : "Workspace already uses the Git branch name.");
      return refreshQuick(changed);
    }, {
      disabled: !hasWorkspace || !branchTitle || branchTitle === workspace?.title,
      title: workspaceUseBranchNameTitle(workspace),
      search: workspaceRenameActionSearchText("useBranch", workspace, "quick setup git branch")
    }),
    quickOverviewControlButton("Use pane", async () => {
      if (!workspace || !paneTitle) return false;
      const changed = await renameWorkspaceTo(paneTitle, workspace.id);
      toast(changed ? "Workspace name set from the active pane." : "Workspace already uses the active pane name.");
      return refreshQuick(changed);
    }, {
      disabled: !hasWorkspace || !paneTitle || paneTitle === workspace?.title,
      title: workspaceUsePaneNameTitle(workspace),
      search: workspaceRenameActionSearchText("usePane", workspace, "quick setup")
    }),
    quickOverviewControlButton("Use page", async () => {
      if (!workspace || !pageTitle) return false;
      const changed = await renameWorkspaceTo(pageTitle, workspace.id);
      toast(changed ? "Workspace name set from page title." : "Workspace already uses this page title.");
      return refreshQuick(changed);
    }, {
      disabled: !hasWorkspace || !pageTitle || pageTitle === workspace?.title,
      title: workspaceUseBrowserPageTitleTitle(workspace, pageTitle),
      search: workspaceRenameActionSearchText("usePageTitle", workspace, "quick setup browser page title")
    }),
    quickOverviewControlButton("Folder", () => chooseWorkspaceFolder(workspace), {
      disabled: !hasWorkspace,
      title: hasWorkspace ? "Choose the active workspace folder." : disabledTitle,
      search: "quick setup workspace folder cwd directory choose change"
    }),
    quickOverviewControlButton("Copy setup", () => copyWorkspaceSetup(workspace), {
      disabled: !hasWorkspace,
      title: hasWorkspace ? "Copy this workspace name, color, and folder as JSON." : disabledTitle,
      search: "quick setup workspace copy setup export name color folder clipboard json"
    }),
    quickOverviewControlButton("Paste setup", () => pasteWorkspaceSetup(workspace), {
      disabled: !hasWorkspace,
      title: hasWorkspace ? "Paste copied workspace setup into the active workspace." : disabledTitle,
      search: "quick setup workspace paste setup import name color folder clipboard json"
    }),
    quickOverviewControlButton("Pane layout", () => openSettingsCategory("workspace", { query: "active pane", focusSearch: false }), {
      disabled: !hasWorkspace,
      title: hasWorkspace ? "Open workspace and active pane layout settings." : disabledTitle,
      search: "quick setup workspace pane layout active pane split size color settings"
    })
  ];
  return quickOverviewControlsPanel({
    className: "quick-overview-workspace",
    title: "Workspace controls",
    meta: hasWorkspace ? `${workspaceName} / ${paneSummary}` : "Open a workspace first",
    search: workspaceRenameActionSearchText("actions", workspace, `quick setup workspace controls rename folder git branch active pane browser page title layout copy paste setup ${workspaceName} ${folderTitle} ${branchTitle} ${paneTitle} ${pageTitle} ${paneSummary}`),
    actions
  });
}

function quickRecentFolderControlsPanel() {
  if (state.recentFolders.length === 0) return null;
  const previewLimit = 4;
  const visibleFolders = state.recentFolders.slice(0, previewLimit);
  const hiddenFolderCount = Math.max(0, state.recentFolders.length - visibleFolders.length);
  const actions = visibleFolders.map((folder) => {
    const name = folderName(folder);
    const shortPath = shortFolderPath(folder);
    return quickOverviewControlButton(name, () => createWorkspaceFromFolderPath(folder), {
      disabled: !folder,
      title: folder ? `Open ${name} as a new workspace.` : "Choose a recent folder first.",
      search: normalizeSettingsQuery(`quick setup recent folder workspace open new reopen directory cwd ${name} ${shortPath} ${folder}`)
    });
  });
  if (hiddenFolderCount > 0) {
    actions.push(quickOverviewControlButton("More", () => openSettingsCategory("workspace", { query: "recent folders", focusSearch: false }), {
      title: `Open all ${state.recentFolders.length} recent workspace folders.`,
      search: normalizeSettingsQuery(`quick setup recent folders more full workspace settings manage directory cwd ${state.recentFolders.join(" ")}`)
    }));
  }
  return quickOverviewControlsPanel({
    className: "quick-overview-workspace",
    title: "Recent folders",
    meta: `${state.recentFolders.length}/${recentFoldersLimit} recent${hiddenFolderCount ? ` / ${hiddenFolderCount} more` : ""}`,
    search: `quick setup recent folders workspace open new directory cwd history ${visibleFolders.map((folder) => `${folderName(folder)} ${shortFolderPath(folder)} ${folder}`).join(" ")}`,
    actions
  });
}

