function terminalSetupSummaryForSettings(settings) {
  const normalized = normalizeSettings({
    ...state.settings,
    ...(settings || {})
  });
  return {
    font: `${optionLabel(terminalFontOptions, normalized.terminalFontFamily, normalized.terminalFontFamily)} ${normalized.terminalFontSize}px`,
    lineHeight: formatLineHeight(normalized.terminalLineHeight),
    padding: `${normalized.terminalPadding}px`,
    history: `${Number(normalized.terminalScrollback || 0).toLocaleString()} history`,
    cursor: `${optionLabel(terminalCursorStyles, normalized.terminalCursorStyle, normalized.terminalCursorStyle)}${normalized.terminalCursorBlink ? " blink" : ""}`,
    shell: optionLabel(terminalProfiles, normalized.terminalProfile, normalized.terminalProfile),
    colors: terminalColorEffectiveForSettings(normalized)
  };
}

function terminalColorEffectiveForSettings(settings) {
  const accent = getComputedStyle(document.documentElement).getPropertyValue("--color-accent").trim()
    || terminalColorDefaults.cursor;
  return {
    background: settings.terminalBackground || terminalColorDefaults.background,
    foreground: settings.terminalForeground || terminalColorDefaults.foreground,
    cursor: settings.terminalCursorColor || accent
  };
}

function terminalSetupPayload(settingsSource = state.settings) {
  const source = {
    ...state.settings,
    ...(settingsSource || {})
  };
  const settings = {};
  for (const key of terminalSetupSettings) settings[key] = source[key];
  return {
    version: 1,
    type: "cmux-terminal-setup",
    summary: terminalSetupSummaryForSettings(settings),
    settings
  };
}

async function copyTerminalSetupPayload(
  payloadModel = terminalSetupPayload(),
  toastText = "Terminal setup copied.",
  dialogMessage = "Clipboard access is unavailable. The current terminal setup is shown below."
) {
  const payload = JSON.stringify(payloadModel, null, 2);
  if (await writeClipboardText(payload)) {
    toast(toastText);
    return true;
  }
  await showTextDialog({
    title: "Terminal setup",
    message: dialogMessage,
    value: payload,
    confirmLabel: "Close",
    multiline: true,
    readOnly: true
  });
  return false;
}

async function copyTerminalSetup() {
  return copyTerminalSetupPayload(terminalSetupPayload(), "Terminal setup copied.");
}

function terminalSetupNumberUpdateFromValue(key, raw) {
  if (raw === null || raw === "" || typeof raw === "boolean" || typeof raw === "object") return null;
  const value = Number(raw);
  if (!Number.isFinite(value)) return null;
  const [min, max] = terminalSetupNumberSettings[key] || [];
  if (!Number.isFinite(min) || !Number.isFinite(max)) return null;
  return clamp(value, min, max);
}

function terminalSetupSettingUpdateFromValue(key, raw) {
  if (key === "terminalFontFamily") return optionIdAllowed(terminalFontOptions, raw) ? raw : null;
  if (key === "terminalCursorStyle") return optionIdAllowed(terminalCursorStyles, raw) ? raw : null;
  if (key === "terminalProfile") return optionIdAllowed(terminalProfiles, raw) ? raw : null;
  if (key === "terminalCursorBlink") return typeof raw === "boolean" ? raw : null;
  if (key === "terminalCustomShell") {
    if (raw === null) return "";
    return typeof raw === "string" ? raw.trim().slice(0, 512) : null;
  }
  if (terminalSetupColorSettings.has(key)) {
    if (raw === "" || raw === null) return "";
    return typeof raw === "string" ? normalizeTerminalColor(raw) || null : null;
  }
  if (Object.prototype.hasOwnProperty.call(terminalSetupNumberSettings, key)) {
    return terminalSetupNumberUpdateFromValue(key, raw);
  }
  return null;
}

function terminalSetupUpdatesFromPayload(payload) {
  const parsed = importedObject(payload);
  const source = importedObject(parsed?.settings) || parsed;
  if (!source) return null;
  const updates = {};
  for (const key of terminalSetupSettings) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;
    const value = terminalSetupSettingUpdateFromValue(key, source[key]);
    if (value === null) return null;
    updates[key] = value;
  }
  return Object.keys(updates).length ? updates : null;
}

function applyTerminalSetupUpdates(updates, options = {}) {
  if (!updates) {
    toast("Clipboard does not contain terminal setup.");
    return false;
  }
  const changed = updateSettings(updates, { immediate: true });
  if (!changed) {
    toast(options.alreadyText || "Terminal setup already matches.");
    return false;
  }
  if (state.inspectorMode === "settings") renderSettingsInspector();
  toast(options.toastText || "Terminal setup applied.");
  return true;
}

function terminalSetupSettingsAreDefault() {
  return settingsKeysMatchDefaults(terminalSetupSettings);
}

function resetTerminalSetupSettings() {
  const updates = {};
  for (const key of terminalSetupSettings) updates[key] = defaultSettings[key];
  const changed = updateSettings(updates, { immediate: true });
  if (!changed) {
    toast("Terminal setup already uses defaults.");
    return false;
  }
  if (state.inspectorMode === "settings") renderSettingsInspector();
  toast("Terminal setup reset.");
  return true;
}

function resetTerminalTextSettings() {
  const updates = {};
  for (const key of terminalTextSettings) updates[key] = defaultSettings[key];
  const changed = updateSettings(updates);
  if (!changed) {
    toast("Terminal text already uses defaults.");
    return false;
  }
  if (state.inspectorMode === "settings") renderSettingsInspector();
  toast("Terminal text reset.");
  return true;
}

async function pasteTerminalSetup() {
  const clipboard = await readClipboardText();
  if (!clipboard) {
    toast("Clipboard is empty.");
    return false;
  }
  try {
    const parsed = JSON.parse(clipboard);
    return applyTerminalSetupUpdates(terminalSetupUpdatesFromPayload(parsed));
  } catch {
    toast("Clipboard does not contain terminal setup.");
    return false;
  }
}

